   149→    let mut current_span = open_event.span();
   150→    let mut current_prefix = None;
   151→    let mut current_suffix = None;
   152→
   153→    while let Some(event) = input.next_token() {
   154→        match event.kind() {
   155→            EventKind::InlineTableOpen
